# Themes for the program can be changed using constants
theme = "imperio_centroafricano"

def clear_terminal():
    """Clears the terminal and returns an escape sequence"""
    print('\033[2J\033[H', end='')

def draw_square(size):
    """Draws a square of the given size"""
    for _ in range(size):
        print("* " * size)

def draw_pattern(size, pattern):
    """Draws a specified pattern on a grid of the given size"""
    for i in range(size):
        row = ""
        for j in range(size):
            if (i + j) % 3 == 1:
                row += "* "
            else:
                row += "  "
        print(row)

def main():
    clear_terminal()
    
    # Sample data
    size = 5
    
    draw_square(size)
    draw_pattern(size, "\n".join(["* "] * size))
    draw_square(size + 2)
    
    if theme == "imperio_centroafricano":
        draw_square(size // 2 - 1)
        for i in range(3):
            draw_square(size // 2 + 3 - i)
        
    if theme == "italia":
        for i in range(size):
            row = ""
            for j in range(size):
                if (i - j) % 5 == 0:
                    row += "*"
                else:
                    row += " "
            print(row)

if __name__ == "__main__":
    main()
